import{_ as a,o as e,c as i,ai as t}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"OAuth","description":"","frontmatter":{"read_when":["你想全面了解 OpenSoul 的 OAuth 流程","你遇到了令牌失效/登出问题","你想了解 setup-token 或 OAuth 认证流程","你想使用多账户或配置文件路由"],"summary":"OpenSoul 中的 OAuth：令牌交换、存储和多账户模式","title":"OAuth","x-i18n":{"generated_at":"2026-02-01T20:23:29Z","model":"claude-opus-4-5","provider":"pi","source_hash":"af714bdadc4a89295a18da1eba5f5b857c8d533ebabe9b0758b722fe60c36124","source_path":"concepts/oauth.md","workflow":14}},"headers":[],"relativePath":"zh-CN/concepts/oauth.md","filePath":"zh-CN/concepts/oauth.md","lastUpdated":1771906665000}'),n={name:"zh-CN/concepts/oauth.md"};function o(l,s,p,h,d,r){return e(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="oauth" tabindex="-1"><a class="header-anchor" href="#oauth">#</a> OAuth</h1><p>OpenSoul 支持通过 OAuth 进行&quot;订阅认证&quot;，适用于提供此功能的提供商（特别是 <strong>OpenAI Codex（ChatGPT OAuth）</strong>）。对于 Anthropic 订阅，请使用 <strong>setup-token</strong> 流程。本页说明：</p><ul><li>OAuth <strong>令牌交换</strong>的工作原理（PKCE）</li><li>令牌<strong>存储</strong>在哪里（以及原因）</li><li>如何处理<strong>多账户</strong>（配置文件 + 按会话覆盖）</li></ul><p>OpenSoul 还支持<strong>提供商插件</strong>，它们自带 OAuth 或 API 密钥流程。通过以下命令运行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="令牌汇聚点-为什么需要它" tabindex="-1"><a class="header-anchor" href="#令牌汇聚点-为什么需要它">#</a> 令牌汇聚点（为什么需要它）</h2><p>OAuth 提供商通常在登录/刷新流程中发放<strong>新的刷新令牌</strong>。某些提供商（或 OAuth 客户端）在为同一用户/应用发放新令牌时，可能会使旧的刷新令牌失效。</p><p>实际症状：</p><ul><li>你通过 OpenSoul <em>和</em> Claude Code / Codex CLI 登录 → 其中一个稍后会随机&quot;登出&quot;</li></ul><p>为减少这种情况，OpenSoul 将 <code>auth-profiles.json</code> 视为<strong>令牌汇聚点</strong>：</p><ul><li>运行时从<strong>同一个位置</strong>读取凭据</li><li>我们可以保留多个配置文件并确定性地路由它们</li></ul><h2 id="存储-令牌存放位置" tabindex="-1"><a class="header-anchor" href="#存储-令牌存放位置">#</a> 存储（令牌存放位置）</h2><p>密钥按<strong>智能体</strong>存储：</p><ul><li>认证配置文件（OAuth + API 密钥）：<code>~/.opensoul/agents/&lt;agentId&gt;/agent/auth-profiles.json</code></li><li>运行时缓存（自动管理；请勿编辑）：<code>~/.opensoul/agents/&lt;agentId&gt;/agent/auth.json</code></li></ul><p>仅用于导入的旧版文件（仍然支持，但不是主存储）：</p><ul><li><code>~/.opensoul/credentials/oauth.json</code>（首次使用时导入到 <code>auth-profiles.json</code>）</li></ul><p>以上所有路径也遵循 <code>$OPENSOUL_STATE_DIR</code>（状态目录覆盖）。完整参考：<a href="/docs/gateway/configuration#auth-storage-oauth--api-keys">/gateway/configuration</a></p><h2 id="anthropic-setup-token-订阅认证" tabindex="-1"><a class="header-anchor" href="#anthropic-setup-token-订阅认证">#</a> Anthropic setup-token（订阅认证）</h2><p>在任意机器上运行 <code>claude setup-token</code>，然后将其粘贴到 OpenSoul 中：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup-token</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropic</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你在其他地方生成了令牌，可以手动粘贴：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> paste-token</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropic</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>验证：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="oauth-交换-登录工作原理" tabindex="-1"><a class="header-anchor" href="#oauth-交换-登录工作原理">#</a> OAuth 交换（登录工作原理）</h2><p>OpenSoul 的交互式登录流程在 <code>@mariozechner/pi-ai</code> 中实现，并集成到向导/命令中。</p><h3 id="anthropic-claude-pro-max-setup-token" tabindex="-1"><a class="header-anchor" href="#anthropic-claude-pro-max-setup-token">#</a> Anthropic（Claude Pro/Max）setup-token</h3><p>流程概要：</p><ol><li>运行 <code>claude setup-token</code></li><li>将令牌粘贴到 OpenSoul</li><li>作为令牌认证配置文件存储（无刷新）</li></ol><p>向导路径为 <code>opensoul onboard</code> → 认证选择 <code>setup-token</code>（Anthropic）。</p><h3 id="openai-codex-chatgpt-oauth" tabindex="-1"><a class="header-anchor" href="#openai-codex-chatgpt-oauth">#</a> OpenAI Codex（ChatGPT OAuth）</h3><p>流程概要（PKCE）：</p><ol><li>生成 PKCE 验证器/质询 + 随机 <code>state</code></li><li>打开 <code>https://auth.openai.com/oauth/authorize?...</code></li><li>尝试在 <code>http://127.0.0.1:1455/auth/callback</code> 捕获回调</li><li>如果回调无法绑定（或你在远程/无头环境中），手动粘贴重定向 URL/代码</li><li>在 <code>https://auth.openai.com/oauth/token</code> 进行交换</li><li>从访问令牌中提取 <code>accountId</code> 并存储 <code>{ access, refresh, expires, accountId }</code></li></ol><p>向导路径为 <code>opensoul onboard</code> → 认证选择 <code>openai-codex</code>。</p><h2 id="刷新-过期" tabindex="-1"><a class="header-anchor" href="#刷新-过期">#</a> 刷新 + 过期</h2><p>配置文件存储 <code>expires</code> 时间戳。</p><p>运行时：</p><ul><li>如果 <code>expires</code> 在未来 → 使用已存储的访问令牌</li><li>如果已过期 → 刷新（在文件锁下）并覆盖已存储的凭据</li></ul><p>刷新流程是自动的；你通常不需要手动管理令牌。</p><h2 id="多账户-配置文件-路由" tabindex="-1"><a class="header-anchor" href="#多账户-配置文件-路由">#</a> 多账户（配置文件）+ 路由</h2><p>两种模式：</p><h3 id="_1-推荐-独立智能体" tabindex="-1"><a class="header-anchor" href="#_1-推荐-独立智能体">#</a> 1）推荐：独立智能体</h3><p>如果你希望&quot;个人&quot;和&quot;工作&quot;永远不交叉，请使用隔离的智能体（独立的会话 + 凭据 + 工作区）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agents</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> work</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agents</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> personal</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>然后按智能体配置认证（向导），并将聊天路由到正确的智能体。</p><h3 id="_2-高级-单个智能体中的多个配置文件" tabindex="-1"><a class="header-anchor" href="#_2-高级-单个智能体中的多个配置文件">#</a> 2）高级：单个智能体中的多个配置文件</h3><p><code>auth-profiles.json</code> 支持同一提供商的多个配置文件 ID。</p><p>选择使用哪个配置文件：</p><ul><li>通过配置顺序全局设置（<code>auth.order</code>）</li><li>通过 <code>/model ...@&lt;profileId&gt;</code> 按会话设置</li></ul><p>示例（会话覆盖）：</p><ul><li><code>/model Opus@anthropic:work</code></li></ul><p>如何查看存在哪些配置文件 ID：</p><ul><li><code>opensoul channels list --json</code>（显示 <code>auth[]</code>）</li></ul><p>相关文档：</p><ul><li><a href="/docs/concepts/model-failover">/concepts/model-failover</a>（轮换 + 冷却规则）</li><li><a href="/docs/tools/slash-commands">/tools/slash-commands</a>（命令界面）</li></ul>`,55)])])}const k=a(n,[["render",o]]);export{u as __pageData,k as default};
